const cell = ctx.runtime.getCell(ctx.runtime.getModel(100), 0, 1, 1);
const inLabel = cell.labels.get('patch');
if (!inLabel || inLabel.t !== 'pin.in') return;
const patch = inLabel.v;
console.log('[on_model100_patch_in] Received patch:', JSON.stringify(patch));
if (patch && patch.version === 'mt.v0' && Array.isArray(patch.records)) {
  ctx.runtime.applyPatch(patch, { allowCreateModel: false });
  console.log('[on_model100_patch_in] Patch applied successfully');
}
