const action = event.action || 'unknown';
const opId = 'm100_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
const payload = {
  version: 'v0',
  type: 'ui_event',
  op_id: opId,
  source_model_id: 100,
  action: action,
  data: event,
  timestamp: Date.now()
};
ctx.runtime.addLabel(m100, 0, 0, 0, { k: 'submit', t: 'pin.table.out', v: payload });
ctx.runtime.addLabel(m100, 0, 0, 2, { k: 'ui_event', t: 'event', v: null });
ctx.rmLabel({ model_id: -10, p: 0, r: 0, c: 0, k: 'run_prepare_model100_submit' });

