const p = ctx.sendMatrix(payload);
if (p && typeof p.then === 'function') {
  p.then(function() { console.log('[forward_model100_submit_from_model0] Matrix send OK, op_id:', payload.op_id); })
   .catch(function(err) {
     console.warn('[forward_model100_submit_from_model0] Matrix send failed (non-fatal):', err.message);
     ctx.runtime.addLabel(m100, 0, 0, 0, { k: 'submit_inflight', t: 'bool', v: false });
     ctx.runtime.addLabel(m100, 0, 0, 0, { k: 'submit_inflight_started_at', t: 'int', v: 0 });
     ctx.runtime.addLabel(m100, 0, 0, 0, { k: 'status', t: 'str', v: 'send_failed' });
   });
} else if (!p) {
  console.warn('[forward_model100_submit_from_model0] Matrix not available, cannot forward event');
